1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	export function processScenario(input: any): unknown {
14	  const items = input.steps[0].items;
15	  if (items.length === 0) {
16	    return { results: [{ premium: PROCESSING_FEE }] };
17	  }
18	  let basePremium: number;
19	  if (items.length === 3 && items.every((item: any) => item.type === "rune")) {
20	    basePremium = 60;
21	  } else {
22	    basePremium = items.reduce(
23	      (sum: number, item: any) => sum + BASE_PREMIUM_BY_TYPE[item.type],
24	      0,
25	    );
26	  }
27	  const premium = Math.ceil(basePremium + basePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE);
28	  return { results: [{ premium }] };
29	}
